import { useEffect, useState } from 'react';

import API from '../services/api';

import StatsCard from '../components/StatsCard';
import Loader from '../components/Loader';
import socket from '../socket';
function Dashboard() {
  const [stats, setStats] = useState(null);

  const [error, setError] = useState('');

  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      setLoading(true);

      const res = await API.get(
        '/dashboard/stats'
      );

      setStats(res.data);

      setError('');
    } catch (err) {
      console.log(err);

      setError(
        'Failed to load dashboard stats.'
      );
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <Loader />;
  }
const user = JSON.parse(
  localStorage.getItem('user')
);
useEffect(() => {
  socket.on(
    'leadCreated',
    () => {
      fetchStats();
    }
  );

  return () => {
    socket.off(
      'leadCreated'
    );
  };
}, []);
  return (
    <div className="dashboard-page">
      <div className="page-header">
        <div>
          <h2>
  {user?.role} Dashboard
</h2>

          <p>
            Monitor leads, admissions and
            counselor performance.
          </p>
        </div>
      </div>

      {error && (
        <div className="error-msg">
          {error}
        </div>
      )}

      {stats && (
        <>
          <div className="stats-grid">
            <StatsCard
              title="Total Leads"
              value={stats.totalLeads}
              color="#6366f1"
            />

            <StatsCard
              title="Counselors"
              value={stats.counselors}
              color="#8b5cf6"
            />

            <StatsCard
              title="Admissions Team"
              value={stats.admissions}
              color="#06b6d4"
            />

            <StatsCard
              title="Admitted Leads"
              value={stats.admittedLeads}
              color="#22c55e"
            />

            <StatsCard
              title="Pending Followups"
              value={stats.followups}
              color="#f97316"
            />
          </div>

          <div className="dashboard-widgets">
            <div className="card">
              <h3>Quick Overview</h3>

              <p>
                Total conversion rate:
              </p>

              <h1>
                {stats.totalLeads > 0
                  ? Math.round(
                      (stats.admittedLeads /
                        stats.totalLeads) *
                        100
                    )
                  : 0}
                %
              </h1>
            </div>

            <div className="card">
              <h3>System Status</h3>

              <p>
                CRM system operational and
                running normally.
              </p>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

export default Dashboard;
